-- Program: Iron Will
-- Category: Hypertrophy/Muscle Building -> hypertrophy
-- Priority: Medium
-- Durations: [8, 12, 16], Sessions: [6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Iron Will',
    'An advanced 16-week hypertrophy program using a PPL (Push/Pull/Legs) split trained twice per week. Four distinct phases: Accumulation, Intensification, Specialization, and Peak. Strategic deload weeks at W4, W8, and W12. Designed for experienced lifters seeking maximum muscle growth.',
    'hypertrophy',
    'advanced',
    16,
    6,
    'push_pull_legs',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Promote active recovery', 'Reduce injury risk']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Iron Will - 8w 6x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    8,
    'Iron Will - 8w 6x/wk',
    'hypertrophy',
    6,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Promote active recovery', 'Reduce injury risk']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Iron Will'
ON CONFLICT DO NOTHING;

