    'Iron Will',
    'Iron Will - 16w 6x/wk',
    'Medium',
    false,
    'An advanced 16-week hypertrophy program using a PPL (Push/Pull/Legs) split trained twice per week. Four distinct phases: Accumulation, Intensification, Specialization, and Peak. Strategic deload weeks at W4, W8, and W12. Designed for experienced lifters seeking maximum muscle growth.',
    'Hypertrophy/Muscle Building'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Iron Will'
  AND pv.duration_weeks = 16
  AND pv.sessions_per_week = 6
ON CONFLICT DO NOTHING;

